import { LlamaCloud } from "@llamaindex/llama-cloud";
import * as fs from "fs";
import * as path from "path";

async function main() {
  const client = new LlamaCloud();

  const filePath = path.join(__dirname, "sample.pdf");
  if (!fs.existsSync(filePath)) {
    throw new Error(`File not found: ${filePath}`);
  }
  const fileStream = fs.createReadStream(filePath);

  console.log("Uploading file...");
  const file = await client.files.create({
    file: fileStream,
    purpose: "parse",
  });

  console.log("Parsing file...");
  const result = await client.parsing.parse({
    file_id: file.id,
    tier: "agentic",
    version: "latest",
    expand: ["markdown"],
  });

  if (!result.markdown || !result.markdown.pages) {
    throw new Error("No markdown pages found in the result");
  }

  const markdownContent = result.markdown.pages
    .map((page: any) => page.markdown)
    .join("\n\n");

  const outputPath = path.join(__dirname, "output.md");
  fs.writeFileSync(outputPath, markdownContent, "utf-8");

  console.log(`Markdown written to ${outputPath}`);
}

main().catch((error) => {
  console.error(error);
  process.exit(1);
});

